private void SetStatus(string message)
        {
            if (_lblStatus == null)
            {
                return;
            }

            var normalized = UiText.Normalize(message);
            _lblStatus.Text = normalized;
            _lblStatus.Foreground = ResolveStatusBrush(normalized);
        }
        private static Brush ResolveStatusBrush(string message)
        {
            if (string.IsNullOrWhiteSpace(message))
            {
                return FgDark;
            }

            if (message.Contains("lỗi", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("không thể", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("error", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("failed", StringComparison.OrdinalIgnoreCase))
            {
                return AccentRed;
            }

            if (message.Contains("cảnh báo", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("hãy", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("chọn", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("hủy", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("warning", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("cancel", StringComparison.OrdinalIgnoreCase))
            {
                return AccentOrange;
            }

            if (message.Contains("đã ", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("thành công", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("sẵn sàng", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("success", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("created", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("updated", StringComparison.OrdinalIgnoreCase) ||
                message.Contains("deleted", StringComparison.OrdinalIgnoreCase))
            {
                return AccentGreen;
            }

            return FgDark;
        }
        private void RefreshBomSummary(bool allowDeferredRetry = true)
        {
            if (!TryCommitAllTenderEdits())
            {
                if (allowDeferredRetry)
                {
                    Dispatcher.BeginInvoke(
                        DispatcherPriority.ContextIdle,
                        new Action(() => RefreshBomSummary(false)));
                }
                else
                {
                    SetStatus("Hãy hoàn tất dữ liệu đang chỉnh sửa trước khi tổng hợp khối lượng.");
                }
                return;
            }

            SyncAllWallRowsSpecData();
            var walls = GetWallModels();
            _project.Accessories = EnsureProjectAccessoriesConfigured();
            var calculator = new TenderBomCalculator();

            var panelSummary = calculator.CalculatePanelSummary(walls);
            _panelSummaryGrid.ItemsSource = panelSummary;

            var accessoryReport = calculator.CalculateAccessoryReport(walls, _project.Accessories);
            _accessoryBasisGrid.ItemsSource = accessoryReport.BasisRows
                .Select((row, index) => TenderAccessoryBasisViewRow.FromReportRow(row, index + 1))
                .ToList();

            _accessorySummaryGrid.ItemsSource = accessoryReport.SummaryRows
                .Select((row, index) => TenderAccessorySummaryViewRow.FromReportRow(row, index + 1))
                .ToList();

            _lblBomFooter.Text =
                $"Cơ sở tính: {accessoryReport.BasisRows.Count} dòng | " +
                $"Tổng hợp phụ kiện: {accessoryReport.SummaryRows.Count} dòng | " +
                $"Khối lượng chốt: {accessoryReport.SummaryRows.Sum(r => r.FinalQuantity):F2}";

            SetStatus(
                $"Khối lượng: {panelSummary.Count} nhóm panel | " +
                $"Tổng {panelSummary.Sum(p => p.EstimatedPanels)} tấm | " +
                $"Phụ kiện chốt {accessoryReport.SummaryRows.Sum(r => r.FinalQuantity):F2}");
        }
private List<TenderAccessory> EnsureProjectAccessoriesConfigured()
        {
            return AccessoryDataManager.NormalizeConfiguredAccessories(_project.Accessories);
        }

