        /// "Refresh is not allowed during an AddNew or EditItem transaction".
        /// </summary>
        private void SafeRefreshWallGrid()
        {
            CommitPendingGridEdits(_wallGrid);
        }

        private bool CommitPendingGridEdits(DataGrid? grid)
        {
            if (grid == null)
                return true;

            try { grid.CommitEdit(DataGridEditingUnit.Cell, true); } catch (System.Exception ex)
            {
                ShopDrawing.Plugin.Core.PluginLogger.Error("Suppressed exception in TenderBomDialog.cs", ex);
            }
            try { grid.CommitEdit(DataGridEditingUnit.Row, true); } catch (System.Exception ex)
            {
                ShopDrawing.Plugin.Core.PluginLogger.Error("Suppressed exception in TenderBomDialog.cs", ex);
            }

            if (grid.ItemsSource == null)
                return true;

            if (CollectionViewSource.GetDefaultView(grid.ItemsSource) is IEditableCollectionView editableView)
            {
                try { if (editableView.IsEditingItem) editableView.CommitEdit(); } catch (System.Exception ex)
            {
                ShopDrawing.Plugin.Core.PluginLogger.Error("Suppressed exception in TenderBomDialog.cs", ex);
            }
                try { if (editableView.IsAddingNew) editableView.CommitNew(); } catch (System.Exception ex)
            {
                ShopDrawing.Plugin.Core.PluginLogger.Error("Suppressed exception in TenderBomDialog.cs", ex);
            }
                return !editableView.IsEditingItem && !editableView.IsAddingNew;
            }

            return true;
        }

        private bool TryCommitAllTenderEdits()
        {
            bool wallReady = CommitPendingGridEdits(_wallGrid);
            bool openingReady = CommitPendingGridEdits(_openingGrid);
            return wallReady && openingReady;
        }

