        private static bool IsVerticalJointColumn(DataGridColumn column)
            => string.Equals(UiText.Normalize(column.Header?.ToString()), "Khe đứng", StringComparison.OrdinalIgnoreCase);

        private static bool IsSuspensionLayoutColumn(DataGridColumn column)
            => string.Equals(UiText.Normalize(column.Header?.ToString()), "Hướng PK", StringComparison.OrdinalIgnoreCase);

        private static bool IsTopPanelTreatmentColumn(DataGridColumn column)
            => string.Equals(UiText.Normalize(column.Header?.ToString()), "Chi tiết đỉnh vách", StringComparison.OrdinalIgnoreCase);

        private static bool IsEndPanelTreatmentColumn(DataGridColumn column)
            => string.Equals(UiText.Normalize(column.Header?.ToString()), "Chi tiết đầu/cuối vách", StringComparison.OrdinalIgnoreCase);

