        /// <summary>
        /// Ensure SD_HIGHLIGHT layer exists, return its ObjectId.
        /// </summary>
        private static Autodesk.AutoCAD.DatabaseServices.ObjectId EnsureHighlightLayer(
            Autodesk.AutoCAD.DatabaseServices.Database db,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            var lt = (Autodesk.AutoCAD.DatabaseServices.LayerTable)tr.GetObject(
                db.LayerTableId, Autodesk.AutoCAD.DatabaseServices.OpenMode.ForRead);

            if (lt.Has("SD_HIGHLIGHT"))
            {
                var layerId = lt["SD_HIGHLIGHT"];
                var existingLayer = (Autodesk.AutoCAD.DatabaseServices.LayerTableRecord)tr.GetObject(
                    layerId,
                    Autodesk.AutoCAD.DatabaseServices.OpenMode.ForWrite);

                // Re-enable the preview layer if it was left off/frozen/locked from a previous CAD session.
                if (existingLayer.IsOff)
                    existingLayer.IsOff = false;
                if (existingLayer.IsFrozen)
                    existingLayer.IsFrozen = false;
                if (existingLayer.IsLocked)
                    existingLayer.IsLocked = false;

                existingLayer.Color = Autodesk.AutoCAD.Colors.Color.FromColorIndex(
                    Autodesk.AutoCAD.Colors.ColorMethod.ByAci, PreviewBoundaryColorIndex);
                existingLayer.LineWeight = Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight211;
                return layerId;
            }

            lt.UpgradeOpen();
            var layer = new Autodesk.AutoCAD.DatabaseServices.LayerTableRecord
            {
                Name = "SD_HIGHLIGHT",
                Color = Autodesk.AutoCAD.Colors.Color.FromColorIndex(
                    Autodesk.AutoCAD.Colors.ColorMethod.ByAci, PreviewBoundaryColorIndex),
                LineWeight = Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight211
            };
            lt.Add(layer);
            tr.AddNewlyCreatedDBObject(layer, true);
            return layer.ObjectId;
        }

        /// <summary>
        /// Highlight source entity only. Avoid temporary overlay objects for stability.
        /// </summary>






        private static Autodesk.AutoCAD.DatabaseServices.Entity? BuildRowRegionPreviewEntity(
            TenderWallRow row,
            Autodesk.AutoCAD.DatabaseServices.Entity sourceEnt)
        {
            if (row.PolygonVertices != null && row.PolygonVertices.Count >= 3)
                return CreatePreviewPolyline(row.PolygonVertices);

            if (sourceEnt is Autodesk.AutoCAD.DatabaseServices.Polyline polyline)
            {
                if (polyline.Closed)
                    return CreatePreviewPolyline(GetPolylineVertices(polyline));

                if (row.Height > 0 && polyline.NumberOfVertices >= 2)
                {
                    return CreatePreviewRectangle(
                        polyline.GetPoint3dAt(0),
                        polyline.GetPoint3dAt(polyline.NumberOfVertices - 1),
                        row.Height);
                }
            }

            if (sourceEnt is Autodesk.AutoCAD.DatabaseServices.Line line && row.Height > 0)
                return CreatePreviewRectangle(line.StartPoint, line.EndPoint, row.Height);

            return null;
        }

        private static Autodesk.AutoCAD.DatabaseServices.Polyline? CreatePreviewRectangle(
            Autodesk.AutoCAD.Geometry.Point3d start,
            Autodesk.AutoCAD.Geometry.Point3d end,
            double heightMm)
        {
            var baseVector = end - start;
            if (baseVector.Length < 1.0 || heightMm <= 0)
                return null;

            var offset = baseVector
                .GetNormal()
                .RotateBy(Math.PI / 2.0, Autodesk.AutoCAD.Geometry.Vector3d.ZAxis)
                .MultiplyBy(heightMm);

            return CreatePreviewPolyline(new List<double[]>
            {
                new[] { start.X, start.Y },
                new[] { end.X, end.Y },
                new[] { end.X + offset.X, end.Y + offset.Y },
                new[] { start.X + offset.X, start.Y + offset.Y }
            });
        }

        private static Autodesk.AutoCAD.DatabaseServices.Polyline? CreatePreviewPolyline(
            IReadOnlyList<double[]> vertices)
        {
            if (vertices.Count < 3)
                return null;

            var polyline = new Autodesk.AutoCAD.DatabaseServices.Polyline();
            for (int index = 0; index < vertices.Count; index++)
            {
                var vertex = vertices[index];
                if (vertex.Length < 2)
                    return null;

                polyline.AddVertexAt(
                    index,
                    new Autodesk.AutoCAD.Geometry.Point2d(vertex[0], vertex[1]),
                    0,
                    0,
                    0);
            }

            polyline.Closed = true;
            return polyline;
        }


        private static List<double[]> GetPreviewVertices(
            TenderWallRow row,
            Autodesk.AutoCAD.DatabaseServices.Entity sourceEnt)
        {
            if (row.PolygonVertices != null && row.PolygonVertices.Count >= 3)
                return row.PolygonVertices.Select(v => v.ToArray()).ToList();

            if (sourceEnt is Autodesk.AutoCAD.DatabaseServices.Polyline polyline)
            {
                if (polyline.Closed)
                    return GetPolylineVertices(polyline);

                if (row.Height > 0 && polyline.NumberOfVertices >= 2)
                {
                    var rectangle = CreatePreviewRectangle(
                        polyline.GetPoint3dAt(0),
                        polyline.GetPoint3dAt(polyline.NumberOfVertices - 1),
                        row.Height);
                    if (rectangle != null)
                        return GetPolylineVertices(rectangle);
                }
            }

            if (sourceEnt is Autodesk.AutoCAD.DatabaseServices.Line line && row.Height > 0)
            {
                var rectangle = CreatePreviewRectangle(line.StartPoint, line.EndPoint, row.Height);
                if (rectangle != null)
                    return GetPolylineVertices(rectangle);
            }

            return new List<double[]>();
        }








        private void AddDevelopedPolylinePreview(
            Autodesk.AutoCAD.DatabaseServices.Polyline polyline,
            TenderWallRow row,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            var baseVertices = GetPolylineVertices(polyline);
            if (baseVertices.Count < 2 || row.Height <= 0)
                return;

            var panelLineKeys = new HashSet<string>(StringComparer.Ordinal);
            void AddPanelDivisionLine(double[] start, double[] end)
            {
                string key = BuildPreviewLineKey(start, end);
                if (!panelLineKeys.Add(key))
                    return;

                AddPreviewLine(
                    new Autodesk.AutoCAD.Geometry.Point3d(start[0], start[1], 0),
                    new Autodesk.AutoCAD.Geometry.Point3d(end[0], end[1], 0),
                    PanelPreviewColorIndex,
                    Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight025,
                    layerId,
                    btr,
                    tr);
            }

            double totalLength = GetPolylineChainLength(baseVertices);
            if (totalLength <= 1.0)
                return;

            var offsetBoundaryPoints = BuildOffsetPolylineBoundary(baseVertices, row.Height);
            if (offsetBoundaryPoints.Count >= 2)
            {
                AddPolylinePreviewBoundary(baseVertices, layerId, btr, tr);
                AddPolylinePreviewBoundary(offsetBoundaryPoints, layerId, btr, tr);
                int connectorCount = Math.Min(baseVertices.Count, offsetBoundaryPoints.Count);
                for (int index = 0; index < connectorCount; index++)
                {
                    AddPreviewLine(
                        new Autodesk.AutoCAD.Geometry.Point3d(baseVertices[index][0], baseVertices[index][1], 0),
                        new Autodesk.AutoCAD.Geometry.Point3d(offsetBoundaryPoints[index][0], offsetBoundaryPoints[index][1], 0),
                        PreviewBoundaryColorIndex,
                        Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight050,
                        layerId,
                        btr,
                        tr);
                }
            }

            if (row.PanelWidth <= 0 || totalLength <= row.PanelWidth)
                return;

            bool horizontalPanels = string.Equals(row.LayoutDirection, "Ngang", StringComparison.OrdinalIgnoreCase);
            if (horizontalPanels)
            {
                for (double offset = row.PanelWidth; offset < row.Height - 1.0; offset += row.PanelWidth)
                {
                    var courseBoundary = BuildOffsetPolylineBoundary(baseVertices, offset);
                    AddPolylinePreviewBoundary(courseBoundary, PanelPreviewColorIndex, layerId, btr, tr);
                }
                return;
            }

            for (double distance = row.PanelWidth; distance < totalLength - 1.0; distance += row.PanelWidth)
            {
                if (!TryGetPointAndNormalAlongPolyline(baseVertices, distance, row.Height, out var start, out var end))
                    continue;

                AddPanelDivisionLine(start, end);
            }

            double walked = 0;
            for (int i = 0; i + 2 < baseVertices.Count; i++)
            {
                double[] segStart = baseVertices[i];
                double[] corner = baseVertices[i + 1];
                double[] segEnd = baseVertices[i + 2];

                double prevDx = corner[0] - segStart[0];
                double prevDy = corner[1] - segStart[1];
                double prevLength = Math.Sqrt(prevDx * prevDx + prevDy * prevDy);
                if (prevLength <= 1.0)
                    continue;

                double nextDx = segEnd[0] - corner[0];
                double nextDy = segEnd[1] - corner[1];
                double nextLength = Math.Sqrt(nextDx * nextDx + nextDy * nextDy);
                if (nextLength <= 1.0)
                {
                    walked += prevLength;
                    continue;
                }

                walked += prevLength;
                double remainderAtCorner = walked % row.PanelWidth;
                if (remainderAtCorner <= 1.0 || row.PanelWidth - remainderAtCorner <= 1.0)
                    continue;

                if (prevLength > remainderAtCorner + 1.0)
                {
                    double prevUx = prevDx / prevLength;
                    double prevUy = prevDy / prevLength;
                    double prevNx = -prevUy;
                    double prevNy = prevUx;
                    double[] prevLineStart =
                    {
                        corner[0] - prevUx * remainderAtCorner,
                        corner[1] - prevUy * remainderAtCorner
                    };
                    double[] prevLineEnd =
                    {
                        prevLineStart[0] + prevNx * row.Height,
                        prevLineStart[1] + prevNy * row.Height
                    };
                    AddPanelDivisionLine(prevLineStart, prevLineEnd);
                }

                double remainingOnNext = row.PanelWidth - remainderAtCorner;
                if (nextLength > remainingOnNext + 1.0)
                {
                    double nextUx = nextDx / nextLength;
                    double nextUy = nextDy / nextLength;
                    double nextNx = -nextUy;
                    double nextNy = nextUx;
                    double[] nextLineStart =
                    {
                        corner[0] + nextUx * remainingOnNext,
                        corner[1] + nextUy * remainingOnNext
                    };
                    double[] nextLineEnd =
                    {
                        nextLineStart[0] + nextNx * row.Height,
                        nextLineStart[1] + nextNy * row.Height
                    };
                    AddPanelDivisionLine(nextLineStart, nextLineEnd);
                }
            }
        }


        private void AddPolylinePreviewBoundary(
            List<double[]> vertices,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            AddPolylinePreviewBoundary(vertices, PreviewBoundaryColorIndex, layerId, btr, tr);
        }

        private void AddPolylinePreviewBoundary(
            List<double[]> vertices,
            short colorIndex,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            for (int i = 0; i + 1 < vertices.Count; i++)
            {
                AddPreviewLine(
                    new Autodesk.AutoCAD.Geometry.Point3d(vertices[i][0], vertices[i][1], 0),
                    new Autodesk.AutoCAD.Geometry.Point3d(vertices[i + 1][0], vertices[i + 1][1], 0),
                    colorIndex,
                    Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight050,
                    layerId,
                    btr,
                    tr);
            }
        }



        private static double[]? TryIntersectOffsetSegments(
            (double[] Start, double[] End, double[] Normal) first,
            (double[] Start, double[] End, double[] Normal) second,
            double offsetDistance)
        {
            double[] a1 = OffsetPoint(first.Start, first.Normal, offsetDistance);
            double[] a2 = OffsetPoint(first.End, first.Normal, offsetDistance);
            double[] b1 = OffsetPoint(second.Start, second.Normal, offsetDistance);
            double[] b2 = OffsetPoint(second.End, second.Normal, offsetDistance);

            double x1 = a1[0], y1 = a1[1];
            double x2 = a2[0], y2 = a2[1];
            double x3 = b1[0], y3 = b1[1];
            double x4 = b2[0], y4 = b2[1];

            double denominator = (x1 - x2) * (y3 - y4) - (y1 - y2) * (x3 - x4);
            if (Math.Abs(denominator) <= 1e-6)
                return null;

            double determinantA = x1 * y2 - y1 * x2;
            double determinantB = x3 * y4 - y3 * x4;
            double px = (determinantA * (x3 - x4) - (x1 - x2) * determinantB) / denominator;
            double py = (determinantA * (y3 - y4) - (y1 - y2) * determinantB) / denominator;
            return new[] { px, py };
        }


        private static bool TryGetPointAndNormalAlongPolyline(
            List<double[]> vertices,
            double distance,
            double height,
            out double[] start,
            out double[] end)
        {
            start = Array.Empty<double>();
            end = Array.Empty<double>();

            if (vertices.Count < 2 || height <= 0)
                return false;

            double walked = 0;
            for (int i = 0; i + 1 < vertices.Count; i++)
            {
                double[] p0 = vertices[i];
                double[] p1 = vertices[i + 1];
                double dx = p1[0] - p0[0];
                double dy = p1[1] - p0[1];
                double segmentLength = Math.Sqrt(dx * dx + dy * dy);
                if (segmentLength <= 1.0)
                    continue;

                if (walked + segmentLength >= distance)
                {
                    double ratio = (distance - walked) / segmentLength;
                    double x = p0[0] + dx * ratio;
                    double y = p0[1] + dy * ratio;
                    double nx = -dy / segmentLength;
                    double ny = dx / segmentLength;
                    start = new[] { x, y };
                    end = new[] { x + nx * height, y + ny * height };
                    return true;
                }

                walked += segmentLength;
            }

            return false;
        }

        private void AddPanelPreviewLines(
            List<double[]> vertices,
            TenderWallRow row,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            if (row.PanelWidth <= 0)
                return;

            if (string.Equals(UiText.Normalize(row.Category), "V\u00e1ch", StringComparison.OrdinalIgnoreCase)
                && vertices.Count >= 3
                && TryAddDevelopedPanelPreviewLines(vertices, row, layerId, btr, tr))
            {
                return;
            }

            bool horizontal = string.Equals(row.LayoutDirection, "Ngang", StringComparison.OrdinalIgnoreCase);
            double min = horizontal ? vertices.Min(v => v[1]) : vertices.Min(v => v[0]);
            double max = horizontal ? vertices.Max(v => v[1]) : vertices.Max(v => v[0]);

            for (double pos = min + row.PanelWidth; pos < max - 1.0; pos += row.PanelWidth)
            {
                var segments = GetScanSegments(vertices, pos, horizontal);
                foreach (var segment in segments)
                {
                    var start = horizontal
                        ? new Autodesk.AutoCAD.Geometry.Point3d(segment.Start, pos, 0)
                        : new Autodesk.AutoCAD.Geometry.Point3d(pos, segment.Start, 0);
                    var end = horizontal
                        ? new Autodesk.AutoCAD.Geometry.Point3d(segment.End, pos, 0)
                        : new Autodesk.AutoCAD.Geometry.Point3d(pos, segment.End, 0);

                    AddPreviewLine(
                        start,
                        end,
                        PanelPreviewColorIndex,
                        Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight025,
                        layerId,
                        btr,
                        tr);
                }
            }
        }

        private bool TryAddDevelopedPanelPreviewLines(
            List<double[]> vertices,
            TenderWallRow row,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            if (row.PolygonVertices == null || row.PolygonVertices.Count < 3)
                return false;

            bool horizontal = string.Equals(row.LayoutDirection, "Ngang", StringComparison.OrdinalIgnoreCase);
            if (!TryBuildDevelopedChains(vertices, horizontal, out var chainA, out var chainB))
                return false;

            if (!horizontal)
            {
                double referenceLengthA = GetPolylineLength(chainA);
                double referenceLengthB = GetPolylineLength(chainB);
                var referenceChain = referenceLengthA <= referenceLengthB ? chainA : chainB;
                var oppositeChain = ReferenceEquals(referenceChain, chainA) ? chainB : chainA;
                double developedLength = GetPolylineLength(referenceChain);
                if (developedLength <= row.PanelWidth + 1.0)
                    return true;

                bool addedAny = false;
                for (double distance = row.PanelWidth; distance < developedLength - 1.0; distance += row.PanelWidth)
                {
                    if (!TryGetPointAndDirectionAlongPolyline(referenceChain, distance, out var start, out var direction))
                        continue;

                    if (!TryIntersectNormalWithPolyline(start, direction, oppositeChain, out var end))
                        continue;

                    AddPreviewLine(
                        new Autodesk.AutoCAD.Geometry.Point3d(start[0], start[1], 0),
                        new Autodesk.AutoCAD.Geometry.Point3d(end[0], end[1], 0),
                        PanelPreviewColorIndex,
                        Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight025,
                        layerId,
                        btr,
                        tr);
                    addedAny = true;
                }

                return addedAny;
            }

            double lengthA = GetPolylineLength(chainA);
            double lengthB = GetPolylineLength(chainB);
            double developmentLength = Math.Max(lengthA, lengthB);
            if (developmentLength <= row.PanelWidth + 1.0)
                return true;

            for (double distance = row.PanelWidth; distance < developmentLength - 1.0; distance += row.PanelWidth)
            {
                double ratio = distance / developmentLength;
                var start = GetPointAlongPolyline(chainA, ratio);
                var end = GetPointAlongPolyline(chainB, ratio);
                if (start == null || end == null)
                    continue;

                AddPreviewLine(
                    new Autodesk.AutoCAD.Geometry.Point3d(start[0], start[1], 0),
                    new Autodesk.AutoCAD.Geometry.Point3d(end[0], end[1], 0),
                    PanelPreviewColorIndex,
                    Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight025,
                    layerId,
                    btr,
                    tr);
            }

            return true;
        }

        private static bool TryBuildDevelopedChains(
            List<double[]> vertices,
            bool horizontal,
            out List<double[]> chainA,
            out List<double[]> chainB)
        {
            chainA = new List<double[]>();
            chainB = new List<double[]>();

            if (vertices.Count < 3)
                return false;

            int startIndex = 0;
            int endIndex = 0;
            double minAxis = double.MaxValue;
            double maxAxis = double.MinValue;

            for (int i = 0; i < vertices.Count; i++)
            {
                double axis = horizontal ? vertices[i][1] : vertices[i][0];
                if (axis < minAxis)
                {
                    minAxis = axis;
                    startIndex = i;
                }

                if (axis > maxAxis)
                {
                    maxAxis = axis;
                    endIndex = i;
                }
            }

            if (startIndex == endIndex)
                return false;

            var forward = BuildVertexChain(vertices, startIndex, endIndex, 1);
            var backward = BuildVertexChain(vertices, startIndex, endIndex, -1);
            if (forward.Count < 2 || backward.Count < 2)
                return false;

            double forwardMeasure = forward.Average(v => horizontal ? v[0] : v[1]);
            double backwardMeasure = backward.Average(v => horizontal ? v[0] : v[1]);

            if (forwardMeasure <= backwardMeasure)
            {
                chainA = forward;
                chainB = backward;
            }
            else
            {
                chainA = backward;
                chainB = forward;
            }

            return true;
        }

        private static List<double[]> BuildVertexChain(
            List<double[]> vertices,
            int startIndex,
            int endIndex,
            int step)
        {
            var chain = new List<double[]>();
            int count = vertices.Count;
            int index = startIndex;

            while (true)
            {
                chain.Add(vertices[index].ToArray());
                if (index == endIndex)
                    break;

                index = (index + step + count) % count;
                if (chain.Count > count + 1)
                    break;
            }

            return chain;
        }



        private static bool TryGetPointAndDirectionAlongPolyline(
            List<double[]> vertices,
            double distance,
            out double[] point,
            out double[] direction)
        {
            point = Array.Empty<double>();
            direction = Array.Empty<double>();

            if (vertices.Count < 2)
                return false;

            double walked = 0;
            for (int i = 0; i + 1 < vertices.Count; i++)
            {
                double[] start = vertices[i];
                double[] end = vertices[i + 1];
                double dx = end[0] - start[0];
                double dy = end[1] - start[1];
                double segmentLength = Math.Sqrt(dx * dx + dy * dy);
                if (segmentLength <= 1e-6)
                    continue;

                if (walked + segmentLength >= distance)
                {
                    double t = (distance - walked) / segmentLength;
                    point = new[]
                    {
                        start[0] + dx * t,
                        start[1] + dy * t
                    };
                    direction = new[]
                    {
                        dx / segmentLength,
                        dy / segmentLength
                    };
                    return true;
                }

                walked += segmentLength;
            }

            if (vertices.Count >= 2)
            {
                double[] start = vertices[^2];
                double[] end = vertices[^1];
                double dx = end[0] - start[0];
                double dy = end[1] - start[1];
                double segmentLength = Math.Sqrt(dx * dx + dy * dy);
                if (segmentLength > 1e-6)
                {
                    point = end.ToArray();
                    direction = new[]
                    {
                        dx / segmentLength,
                        dy / segmentLength
                    };
                    return true;
                }
            }

            return false;
        }

        private static bool TryIntersectNormalWithPolyline(
            double[] origin,
            double[] direction,
            List<double[]> polyline,
            out double[] intersection)
        {
            intersection = Array.Empty<double>();
            if (origin.Length < 2 || direction.Length < 2 || polyline.Count < 2)
                return false;

            double nx = -direction[1];
            double ny = direction[0];
            double[] centroid = GetPolylineCentroid(polyline);
            double towardCentroid = (centroid[0] - origin[0]) * nx + (centroid[1] - origin[1]) * ny;
            if (towardCentroid < 0)
            {
                nx = -nx;
                ny = -ny;
            }

            double bestT = double.MaxValue;
            bool found = false;
            for (int i = 0; i + 1 < polyline.Count; i++)
            {
                if (!TryIntersectRayWithSegment(
                        origin[0],
                        origin[1],
                        nx,
                        ny,
                        polyline[i][0],
                        polyline[i][1],
                        polyline[i + 1][0],
                        polyline[i + 1][1],
                        out double rayT,
                        out _))
                {
                    continue;
                }

                if (rayT <= 1.0 || rayT >= bestT)
                    continue;

                bestT = rayT;
                found = true;
            }

            if (!found)
                return false;

            intersection = new[]
            {
                origin[0] + nx * bestT,
                origin[1] + ny * bestT
            };
            return true;
        }


        private static bool TryIntersectRayWithSegment(
            double px,
            double py,
            double rx,
            double ry,
            double ax,
            double ay,
            double bx,
            double by,
            out double rayT,
            out double segmentU)
        {
            rayT = 0;
            segmentU = 0;

            double sx = bx - ax;
            double sy = by - ay;
            double denominator = Cross(rx, ry, sx, sy);
            if (Math.Abs(denominator) <= 1e-6)
                return false;

            double qpx = ax - px;
            double qpy = ay - py;
            rayT = Cross(qpx, qpy, sx, sy) / denominator;
            segmentU = Cross(qpx, qpy, rx, ry) / denominator;
            return rayT >= 0 && segmentU >= -1e-6 && segmentU <= 1 + 1e-6;
        }


        private void AddSuspensionPreviewLines(
            List<double[]> vertices,
            bool runAlongX,
            IReadOnlyList<double> positions,
            double spacingMm,
            string linePrefix,
            short colorIndex,
            Autodesk.AutoCAD.DatabaseServices.LineWeight lineWeight,
            bool useCircleMarker,
            bool drawMarkers,
            bool drawLabels,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            for (int index = 0; index < positions.Count; index++)
            {
                double pos = positions[index];
                var segments = GetScanSegments(vertices, pos, runAlongX);
                foreach (var segment in segments)
                {
                    var start = runAlongX
                        ? new Autodesk.AutoCAD.Geometry.Point3d(segment.Start, pos, 0)
                        : new Autodesk.AutoCAD.Geometry.Point3d(pos, segment.Start, 0);
                    var end = runAlongX
                        ? new Autodesk.AutoCAD.Geometry.Point3d(segment.End, pos, 0)
                        : new Autodesk.AutoCAD.Geometry.Point3d(pos, segment.End, 0);

                    AddPreviewLine(start, end, colorIndex, lineWeight, layerId, btr, tr);
                    if (drawMarkers)
                    {
                        AddSuspensionPointMarkers(
                            start,
                            end,
                            colorIndex,
                            useCircleMarker,
                            layerId,
                            btr,
                            tr);
                    }

                    if (drawLabels)
                    {
                        AddSuspensionLineLabel(
                            start,
                            end,
                            $"{linePrefix}{index + 1} @{spacingMm:F0}",
                            colorIndex,
                            layerId,
                            btr,
                            tr);
                    }
                }
            }
        }

        private void AddSuspensionPreviewLines(
            List<double[]> vertices,
            bool runAlongX,
            bool divideFromMaxSide,
            double cycleSpacingMm,
            double initialOffsetMm,
            int lineCount,
            string linePrefix,
            short colorIndex,
            Autodesk.AutoCAD.DatabaseServices.LineWeight lineWeight,
            bool useCircleMarker,
            bool drawMarkers,
            bool drawLabels,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            var positions = BuildSuspensionLinePositions(vertices, runAlongX, divideFromMaxSide, cycleSpacingMm, initialOffsetMm, lineCount);
            AddSuspensionPreviewLines(
                vertices,
                runAlongX,
                positions,
                initialOffsetMm,
                linePrefix,
                colorIndex,
                lineWeight,
                useCircleMarker,
                drawMarkers,
                drawLabels,
                layerId,
                btr,
                tr);
        }

        private static List<double> BuildSuspensionLinePositions(
            List<double[]> vertices,
            bool runAlongX,
            bool divideFromMaxSide,
            double cycleSpacingMm,
            double initialOffsetMm,
            int lineCount)
        {
            var positions = new List<double>();
            if (lineCount <= 0 || cycleSpacingMm <= 0 || initialOffsetMm <= 0)
                return positions;

            double min = runAlongX ? vertices.Min(v => v[1]) : vertices.Min(v => v[0]);
            double max = runAlongX ? vertices.Max(v => v[1]) : vertices.Max(v => v[0]);
            if (max - min <= initialOffsetMm)
                return positions;

            const double edgeOffset = 0.5;
            double start = divideFromMaxSide
                ? max - initialOffsetMm
                : min + initialOffsetMm;
            double step = divideFromMaxSide ? -cycleSpacingMm : cycleSpacingMm;

            for (double pos = start;
                 positions.Count < lineCount && pos > min + edgeOffset - 1e-6 && pos < max - edgeOffset + 1e-6;
                 pos += step)
            {
                if (positions.Count == 0 || Math.Abs(positions[positions.Count - 1] - pos) > 1.0)
                    positions.Add(pos);
            }

            return positions;
        }

        private static List<(double Start, double End)> GetScanSegments(
            List<double[]> vertices,
            double scanPos,
            bool horizontalLine)
        {
            var intersections = new List<double>();
            int count = vertices.Count;

            for (int i = 0; i < count; i++)
            {
                var p1 = vertices[i];
                var p2 = vertices[(i + 1) % count];

                double s1 = horizontalLine ? p1[1] : p1[0];
                double s2 = horizontalLine ? p2[1] : p2[0];
                double m1 = horizontalLine ? p1[0] : p1[1];
                double m2 = horizontalLine ? p2[0] : p2[1];

                if ((s1 <= scanPos && s2 > scanPos) || (s2 <= scanPos && s1 > scanPos))
                {
                    double t = (scanPos - s1) / (s2 - s1);
                    intersections.Add(m1 + t * (m2 - m1));
                }
            }

            intersections.Sort();
            var segments = new List<(double Start, double End)>();
            for (int i = 0; i + 1 < intersections.Count; i += 2)
            {
                double start = intersections[i];
                double end = intersections[i + 1];
                if (end - start > 1.0)
                    segments.Add((start, end));
            }

            return segments;
        }

        private void AddPreviewLine(
            Autodesk.AutoCAD.Geometry.Point3d start,
            Autodesk.AutoCAD.Geometry.Point3d end,
            short colorIndex,
            Autodesk.AutoCAD.DatabaseServices.LineWeight lineWeight,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            var line = new Autodesk.AutoCAD.DatabaseServices.Line(start, end)
            {
                LayerId = layerId,
                ColorIndex = colorIndex,
                LineWeight = lineWeight
            };

            btr.AppendEntity(line);
            tr.AddNewlyCreatedDBObject(line, true);
            _previewEntityIds.Add(line.ObjectId);
        }

        private void AddSuspensionPointMarkers(
            Autodesk.AutoCAD.Geometry.Point3d start,
            Autodesk.AutoCAD.Geometry.Point3d end,
            short colorIndex,
            bool useCircleMarker,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            double length = start.DistanceTo(end);
            if (length <= 1.0)
                return;

            int pointCount = Math.Max(1, (int)Math.Ceiling(length / TenderBomCalculator.ColdStorageSuspensionPointSpacingMm));
            double actualSpacing = length / pointCount;
            var direction = (end - start).GetNormal();
            var normal = new Autodesk.AutoCAD.Geometry.Vector3d(-direction.Y, direction.X, 0.0);
            const double markerSize = 60.0;

            for (int i = 0; i < pointCount; i++)
            {
                double distance = actualSpacing * (i + 0.5);
                var center = start + (direction * distance);

                if (useCircleMarker)
                {
                    AddPreviewCircle(center, markerSize, colorIndex, layerId, btr, tr);
                }
                else
                {
                    AddPreviewCross(center, direction, normal, markerSize, colorIndex, layerId, btr, tr);
                }
            }
        }

        private void AddPreviewCircle(
            Autodesk.AutoCAD.Geometry.Point3d center,
            double radius,
            short colorIndex,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            var circle = new Autodesk.AutoCAD.DatabaseServices.Circle(center, Autodesk.AutoCAD.Geometry.Vector3d.ZAxis, radius)
            {
                LayerId = layerId,
                ColorIndex = colorIndex,
                LineWeight = Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight025
            };

            btr.AppendEntity(circle);
            tr.AddNewlyCreatedDBObject(circle, true);
            _previewEntityIds.Add(circle.ObjectId);
        }

        private void AddPreviewCross(
            Autodesk.AutoCAD.Geometry.Point3d center,
            Autodesk.AutoCAD.Geometry.Vector3d direction,
            Autodesk.AutoCAD.Geometry.Vector3d normal,
            double markerSize,
            short colorIndex,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            AddPreviewLine(
                center - direction * markerSize,
                center + direction * markerSize,
                colorIndex,
                Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight025,
                layerId,
                btr,
                tr);

            AddPreviewLine(
                center - normal * markerSize,
                center + normal * markerSize,
                colorIndex,
                Autodesk.AutoCAD.DatabaseServices.LineWeight.LineWeight025,
                layerId,
                btr,
                tr);
        }

        private void AddSuspensionLineLabel(
            Autodesk.AutoCAD.Geometry.Point3d start,
            Autodesk.AutoCAD.Geometry.Point3d end,
            string text,
            short colorIndex,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            var direction = end - start;
            if (direction.Length <= 1.0)
                return;

            var normal = new Autodesk.AutoCAD.Geometry.Vector3d(-direction.Y, direction.X, 0.0).GetNormal();
            var labelPoint = start + direction.MultiplyBy(0.08) + normal.MultiplyBy(140.0);
            AddPreviewText(labelPoint, text, colorIndex, 140.0, layerId, btr, tr);
        }

        private void AddPreviewSummaryText(
            List<double[]> vertices,
            TenderWallRow row,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            double minX = vertices.Min(v => v[0]);
            double maxY = vertices.Max(v => v[1]);
            string dropText = row.CableDropLengthMm > 0 ? $"Ty thả {row.CableDropLengthMm:F0}" : "Ty thả ?";
            string text = $"PW{row.PanelWidth} | {row.PanelThickness}T | {dropText}";
            var point = new Autodesk.AutoCAD.Geometry.Point3d(minX + 180.0, maxY - 180.0, 0);
            AddPreviewText(point, text, PreviewSummaryTextColorIndex, 160.0, layerId, btr, tr);
        }

        private void AddPreviewText(
            Autodesk.AutoCAD.Geometry.Point3d position,
            string text,
            short colorIndex,
            double height,
            Autodesk.AutoCAD.DatabaseServices.ObjectId layerId,
            Autodesk.AutoCAD.DatabaseServices.BlockTableRecord btr,
            Autodesk.AutoCAD.DatabaseServices.Transaction tr)
        {
            var dbText = new Autodesk.AutoCAD.DatabaseServices.DBText
            {
                Position = position,
                Height = height,
                TextString = text,
                LayerId = layerId,
                ColorIndex = colorIndex,
                TextStyleId = BlockManager.EnsureArialStyle(btr.Database, tr)
            };

            btr.AppendEntity(dbText);
            tr.AddNewlyCreatedDBObject(dbText, true);
            _previewEntityIds.Add(dbText.ObjectId);
        }

        private void OnEditAccessories(object sender, RoutedEventArgs e)
        {
            try
            {
                _project.Accessories = AccessoryDataManager.NormalizeConfiguredAccessories(_project.Accessories);
                var dialog = new TenderAccessoryEditorDialog(
                    _project.Accessories,
                    _project.Specs.Select(spec => spec.Key));

                dialog.Owner = this;
                bool? result = dialog.ShowDialog();
                if (result != true)
                    return;

                _project.Accessories = dialog.GetAccessories();
                RefreshBomSummary();
                SetStatus($"Đã cập nhật {_project.Accessories.Count} dòng phụ kiện");
            }
            catch (Exception ex)
            {
                SetStatus($"Lỗi sửa phụ kiện: {ex.Message}");
            }
        }

