        private static DataGridTextColumn Col(string header, string binding, double width,
            string? format = null)
        {
            var col = new DataGridTextColumn
            {
                Header = UiText.Normalize(header),
                Binding = new Binding(binding) { StringFormat = format },
                Width = new DataGridLength(width)
            };

            var elementStyle = new Style(typeof(TextBlock));
            elementStyle.Setters.Add(new Setter(TextBlock.TextTrimmingProperty, TextTrimming.CharacterEllipsis));
            elementStyle.Setters.Add(new Setter(FrameworkElement.ToolTipProperty, new Binding(binding)));
            col.ElementStyle = elementStyle;

            var editingStyle = new Style(typeof(TextBox));
            editingStyle.Setters.Add(new Setter(FrameworkElement.ToolTipProperty, new Binding(binding)));
            col.EditingElementStyle = editingStyle;

            return col;
        }

        private static DataGridTextColumn ColCableDrop(string header, string binding, double width,
            string? format = null)
        {
            var col = Col(header, binding, width, format);

            var cellStyle = new Style(typeof(DataGridCell));
            cellStyle.Triggers.Add(new DataTrigger
            {
                Binding = new Binding(nameof(TenderWallRow.IsCableDropEditable)),
                Value = false,
                Setters =
                {
                    new Setter(UIElement.IsEnabledProperty, false),
                    new Setter(Control.BackgroundProperty, new SolidColorBrush(Color.FromRgb(240, 240, 240))),
                    new Setter(Control.ForegroundProperty, Brushes.DimGray)
                }
            });
            col.CellStyle = cellStyle;

            var editingStyle = new Style(typeof(TextBox));
            editingStyle.Triggers.Add(new DataTrigger
            {
                Binding = new Binding(nameof(TenderWallRow.IsCableDropEditable)),
                Value = false,
                Setters =
                {
                    new Setter(TextBox.IsReadOnlyProperty, true),
                    new Setter(UIElement.IsEnabledProperty, false),
                    new Setter(Control.BackgroundProperty, new SolidColorBrush(Color.FromRgb(240, 240, 240))),
                    new Setter(Control.ForegroundProperty, Brushes.DimGray)
                }
            });
            col.EditingElementStyle = editingStyle;

            return col;
        }

        private static DataGridTextColumn ColVerticalJoint(string header, string binding, double width,
