    public class TenderWallRow : INotifyPropertyChanged
    {
        public int Index { get; set; }
        public string Category { get; set; } = "V\u00e1ch";
        public string Floor { get; set; } = "";
        public string Name { get; set; } = "";
        public double Length { get; set; }
        public double Height { get; set; }
        public string SpecKey { get; set; } = "";
        public int PanelWidth { get; set; } = 1100;
        public int PanelThickness { get; set; } = 50;
        public string LayoutDirection { get; set; } = "D\u1ecdc";
        public string Application { get; set; } = "Ngo\u00e0i nh\u00e0";
        public double CableDropLengthMm { get; set; }
        private string NormalizedCategory => UiText.Normalize(Category);
        private string NormalizedApplication => UiText.Normalize(Application);
        public bool IsCableDropEditable => string.Equals(NormalizedCategory, "Tr\u1ea7n", StringComparison.OrdinalIgnoreCase);
        public bool IsSuspensionLayoutEditable => string.Equals(NormalizedCategory, "Tr\u1ea7n", StringComparison.OrdinalIgnoreCase);
        public bool IsTopPanelTreatmentEditable => string.Equals(NormalizedCategory, "V\u00e1ch", StringComparison.OrdinalIgnoreCase);
        public bool IsEndPanelTreatmentEditable => string.Equals(NormalizedCategory, "V\u00e1ch", StringComparison.OrdinalIgnoreCase);
        public bool IsBottomPanelTreatmentFixed =>
            string.Equals(NormalizedCategory, "V\u00e1ch", StringComparison.OrdinalIgnoreCase)
            && string.Equals(NormalizedApplication, "Kho l\u1ea1nh", StringComparison.OrdinalIgnoreCase);
        public bool IsBottomPanelTreatmentEditable => false;
        public bool IsVerticalJointEditable =>
            string.Equals(NormalizedCategory, "V\u00e1ch", StringComparison.OrdinalIgnoreCase)
            && string.Equals(NormalizedApplication, "Ngo\u00e0i nh\u00e0", StringComparison.OrdinalIgnoreCase);
        public bool ColdStorageDivideFromMaxSide { get; set; }
        public string SuspensionLayoutDirection { get; set; } = string.Empty;
        public string TopPanelTreatment { get; set; } = TenderWall.TopPanelTreatmentNone;
        public string EndPanelTreatment { get; set; } = TenderWall.EndPanelTreatmentNone;
        public string BottomPanelTreatment { get; set; } = TenderWall.BottomPanelTreatmentNone;
        public bool TopEdgeExposed { get; set; } = true;
        public bool BottomEdgeExposed { get; set; } = true;
        public bool StartEdgeExposed { get; set; }
        public bool EndEdgeExposed { get; set; }
        public int OutsideCornerCount { get; set; }
        public int InsideCornerCount { get; set; }
        public string? CadHandle { get; set; }
        /// <summary>So duong noi chay doc (Ngang layout) - dung tinh Omega, Foam, Gioang xop.</summary>
        public int VerticalJointCount { get; set; }
        public List<TenderOpening> Openings { get; set; } = new();
        public List<double[]>? PolygonVertices { get; set; }

        // Track previous category for auto-reset LayoutDirection
        internal string? _prevCategory;

        /// <summary>ChiÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Âu chia tÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂºÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¥m (mm) ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â DÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Âc: chiÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Âu dÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â i, Ngang: chiÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Âu cao</summary>
        private double DivisionSpan => LayoutDirection == "Ngang" ? Height : Length;
        /// <summary>ChiÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Âu span tÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂºÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¥m (mm) ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â DÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Âc: chiÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Âu cao, Ngang: chiÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â»ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Âu dÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â i</summary>
        private double PanelSpan => LayoutDirection == "Ngang" ? Length : Height;

        public string WallAreaM2Display => (Length * Height / 1_000_000.0).ToString("F2");
        public string OpeningAreaM2Display => Openings.Sum(o => o.TotalAreaM2).ToString("F2");
        public string NetAreaM2Display => Math.Max(0, Length * Height / 1e6 - Openings.Sum(o => o.TotalAreaM2)).ToString("F2");
        public string EstimatedPanelCountDisplay
        {
            get
            {
                if (PanelWidth <= 0 || DivisionSpan <= 0) return "0";
                return ((int)Math.Ceiling(DivisionSpan / PanelWidth)).ToString();
            }
        }

        public void Refresh()
        {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(Category)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(Length)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(Height)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(PanelWidth)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(PanelThickness)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(LayoutDirection)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(Application)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(CableDropLengthMm)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(IsCableDropEditable)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(IsSuspensionLayoutEditable)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(IsTopPanelTreatmentEditable)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(IsEndPanelTreatmentEditable)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(IsBottomPanelTreatmentFixed)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(IsBottomPanelTreatmentEditable)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(IsVerticalJointEditable)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(ColdStorageDivideFromMaxSide)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(SuspensionLayoutDirection)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(TopPanelTreatment)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(EndPanelTreatment)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(BottomPanelTreatment)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(TopEdgeExposed)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(BottomEdgeExposed)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(StartEdgeExposed)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(EndEdgeExposed)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(WallAreaM2Display)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(OpeningAreaM2Display)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(NetAreaM2Display)));
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(EstimatedPanelCountDisplay)));
        }

        public void NormalizeCableDropLength()
        {
            if (!IsCableDropEditable)
                CableDropLengthMm = 0;
        }

        public void NormalizeSuspensionLayoutDirection()
        {
            if (!IsSuspensionLayoutEditable)
            {
                SuspensionLayoutDirection = string.Empty;
                return;
            }

            if (string.IsNullOrWhiteSpace(SuspensionLayoutDirection))
                SuspensionLayoutDirection = LayoutDirection;
        }

        public void NormalizeTopPanelTreatment()
        {
            if (!IsTopPanelTreatmentEditable)
            {
                TopPanelTreatment = TenderWall.TopPanelTreatmentNone;
                TopEdgeExposed = false;
                return;
            }

            TopPanelTreatment = TenderWall.NormalizeTopPanelTreatment(TopPanelTreatment, TopEdgeExposed);
            TopEdgeExposed = !string.Equals(TopPanelTreatment, TenderWall.TopPanelTreatmentNone, StringComparison.OrdinalIgnoreCase);
        }

        public void NormalizeEndPanelTreatment()
        {
            if (!IsEndPanelTreatmentEditable)
            {
                EndPanelTreatment = TenderWall.EndPanelTreatmentNone;
                StartEdgeExposed = false;
                EndEdgeExposed = false;
                return;
            }

            EndPanelTreatment = TenderWall.NormalizeEndPanelTreatment(
                EndPanelTreatment,
                StartEdgeExposed || EndEdgeExposed);
        }

        public void NormalizeBottomPanelTreatment()
        {
            if (IsBottomPanelTreatmentFixed)
            {
                BottomPanelTreatment = BottomEdgeExposed
                    ? TenderWall.BottomPanelTreatmentCurb
                    : TenderWall.BottomPanelTreatmentNone;
                return;
            }

            if (!IsBottomPanelTreatmentEditable)
            {
                BottomPanelTreatment = TenderWall.BottomPanelTreatmentNone;
                return;
            }

            BottomPanelTreatment = TenderWall.NormalizeBottomPanelTreatment(BottomPanelTreatment, BottomEdgeExposed);
            BottomEdgeExposed = !string.Equals(BottomPanelTreatment, TenderWall.BottomPanelTreatmentNone, StringComparison.OrdinalIgnoreCase);
        }

        public void SyncOpenings(IEnumerable<TenderOpeningRow> rows)
        {
            Openings = rows.Select(r => new TenderOpening
            {
                Type = r.Type, Width = r.Width, Height = r.Height, Quantity = r.Quantity
            }).ToList();
        }

        public TenderWall ToModel()
        {
            NormalizeCableDropLength();
            NormalizeSuspensionLayoutDirection();
            NormalizeTopPanelTreatment();
            NormalizeEndPanelTreatment();
            NormalizeBottomPanelTreatment();
            return new TenderWall
            {
                Category = UiText.Normalize(Category), Floor = Floor, Name = Name,
                Length = Length, Height = Height, SpecKey = SpecKey,
                PanelWidth = PanelWidth, PanelThickness = PanelThickness,
                LayoutDirection = LayoutDirection,
                Application = UiText.Normalize(Application),
                CableDropLengthMm = CableDropLengthMm,
                ColdStorageDivideFromMaxSide = ColdStorageDivideFromMaxSide,
                SuspensionLayoutDirection = SuspensionLayoutDirection,
                TopPanelTreatment = TopPanelTreatment,
                EndPanelTreatment = EndPanelTreatment,
                BottomPanelTreatment = BottomPanelTreatment,
                TopEdgeExposed = TopEdgeExposed,
                BottomEdgeExposed = BottomEdgeExposed,
                StartEdgeExposed = StartEdgeExposed,
                EndEdgeExposed = EndEdgeExposed,
                OutsideCornerCount = OutsideCornerCount,
                InsideCornerCount = InsideCornerCount,
                CadHandle = CadHandle, Openings = Openings,
                VerticalJointCount = VerticalJointCount,
                PolygonVertices = PolygonVertices
            };
        }


        public static TenderWallRow FromModel(TenderWall w, int index)
        {
            var row = new TenderWallRow
            {
                Index = index, Category = UiText.Normalize(w.Category), Floor = w.Floor, Name = w.Name,
                Length = w.Length, Height = w.Height, SpecKey = w.SpecKey,
                PanelWidth = w.PanelWidth, PanelThickness = w.PanelThickness,
                LayoutDirection = w.LayoutDirection,
                Application = UiText.Normalize(w.Application),
                CableDropLengthMm = w.CableDropLengthMm,
                ColdStorageDivideFromMaxSide = w.ColdStorageDivideFromMaxSide,
                SuspensionLayoutDirection = w.SuspensionLayoutDirection,
                TopPanelTreatment = TenderWall.NormalizeTopPanelTreatment(w.TopPanelTreatment, w.TopEdgeExposed),
                EndPanelTreatment = TenderWall.NormalizeEndPanelTreatment(w.EndPanelTreatment, w.StartEdgeExposed || w.EndEdgeExposed),
                BottomPanelTreatment = TenderWall.NormalizeBottomPanelTreatment(w.BottomPanelTreatment, w.BottomEdgeExposed),
                TopEdgeExposed = w.TopEdgeExposed,
                BottomEdgeExposed = w.BottomEdgeExposed,
                StartEdgeExposed = w.StartEdgeExposed,
                EndEdgeExposed = w.EndEdgeExposed,
                OutsideCornerCount = w.OutsideCornerCount,
                InsideCornerCount = w.InsideCornerCount,
                CadHandle = w.CadHandle, Openings = w.Openings,
                PolygonVertices = w.PolygonVertices,
                VerticalJointCount = w.VerticalJointCount,
                _prevCategory = UiText.Normalize(w.Category)
            };
            row.NormalizeSuspensionLayoutDirection();
            row.NormalizeCableDropLength();
            row.NormalizeTopPanelTreatment();
            row.NormalizeEndPanelTreatment();
            row.NormalizeBottomPanelTreatment();
            return row;
        }

        public event PropertyChangedEventHandler? PropertyChanged;
    }

    public class TenderOpeningRow : INotifyPropertyChanged
    {
        public string Type { get; set; } = "Cửa đi";
        public double Width { get; set; }
        public double Height { get; set; }
        public int Quantity { get; set; } = 1;

        public string TotalAreaDisplay => (Width * Height * Quantity / 1_000_000.0).ToString("F2");

        public void Refresh()
        {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(TotalAreaDisplay)));
        }

        public event PropertyChangedEventHandler? PropertyChanged;
    }

